// ══════════════════════════════════════════════════
//  CONFIGURA AQUÍ
// ══════════════════════════════════════════════════
const CONFIG = {
  GOOGLE_SHEET_ID:      'TU_SHEET_ID_AQUI',
  SUPABASE_URL:         'https://TUPROYECTO.supabase.co',    // Settings → API → Project URL
  SUPABASE_ANON_KEY:    'eyJhbGci...',                        // Settings → API → anon/public key
  GOOGLE_PAGESPEED_KEY: 'TU_API_KEY_AQUI'                    // Misma key de Google Cloud (habilita PageSpeed Insights API)
};
return [{ json: CONFIG }];

// Filtra filas válidas y añade la config a cada item
const config = $('⚙️ Config').first().json;
const items  = $input.all();

const validas = items
  .filter(item => item.json.Nombre && item.json.Nombre.trim())
  .map(item => ({ json: { ...item.json, _config: config } }));

if (validas.length === 0) throw new Error('No hay datos en el Google Sheet.');
return validas;

// Combina HTML análisis + PageSpeed + datos del Sheet
// para generar el análisis SEO completo de la clínica

const clinica   = $('🔄 Una clínica a la vez').item.json;
const config    = clinica._config;

// HTML de la web (puede estar vacío si falló el fetch)
const htmlRaw   = String($('🌍 Descargar web').item?.json?.data || $('🌍 Descargar web').item?.json?.body || '');
const html      = htmlRaw.substring(0, 6000).toLowerCase();

// PageSpeed data
const psJson       = $('⚡ PageSpeed Insights API').item?.json || {};
const cats         = psJson.lighthouseResult?.categories || {};
const seoPerf      = Math.round((cats.performance?.score || 0) * 100);
const seoScore     = Math.round((cats.seo?.score || 0) * 100);

// ── Análisis de la web ─────────────────────────────────
const web         = clinica.Web || '';
const tieneWeb    = web.length > 4 && web.includes('.');
const valoracion  = parseFloat(clinica['Valoración'] || '0');
const nResenas    = parseInt(clinica['Nº Reseñas'] || '0');

const checks = [
  { type: 'web',        ok: tieneWeb,                           label: tieneWeb ? 'Tiene página web' : 'Sin página web propia' },
  { type: 'https',      ok: web.startsWith('https://'),         label: web.startsWith('https://') ? 'HTTPS activado' : 'Sin HTTPS (penaliza en Google)' },
  { type: 'cita',       ok: /cita|reserva|appointment|booking/i.test(html),  label: /cita|reserva|appointment|booking/i.test(html) ? 'Formulario de cita online' : 'Sin cita online (pierde pacientes nocturnos)' },
  { type: 'whatsapp',   ok: /whatsapp|wa\.me/i.test(html),     label: /whatsapp|wa\.me/i.test(html) ? 'Botón WhatsApp presente' : 'Sin WhatsApp (67% prefiere app a llamar)' },
  { type: 'blog',       ok: /\/blog|\/articulos|\/noticias/i.test(html), label: /\/blog|\/articulos|\/noticias/i.test(html) ? 'Tiene blog/contenido SEO' : 'Sin blog (invisible en Google para búsquedas informacionales)' },
  { type: 'testimonios',ok: /testimonio|opiniones|pacientes/i.test(html),    label: /testimonio|opiniones|pacientes/i.test(html) ? 'Muestra testimonios' : 'Sin testimonios en web (reduce conversión)' },
  { type: 'schema',     ok: /application\/ld\+json/i.test(htmlRaw),          label: /application\/ld\+json/i.test(htmlRaw) ? 'Schema markup presente' : 'Sin schema markup (no aparecen estrellas en Google)' },
  { type: 'meta',       ok: /<meta[^>]*name=["']description["']/i.test(htmlRaw), label: /<meta[^>]*name=["']description["']/i.test(htmlRaw) ? 'Meta descripción configurada' : 'Sin meta descripción (Google ignora la página)' },
  { type: 'valoracion', ok: valoracion >= 4.3,                  label: valoracion >= 4.3 ? `Buena valoración (${valoracion}⭐)` : `Valoración baja (${valoracion}⭐ — media del sector: 4.3)` },
  { type: 'resenas',    ok: nResenas >= 30,                     label: nResenas >= 30 ? `Buenas reseñas (${nResenas})` : `Pocas reseñas (${nResenas} — competidores con más aparecen primero)` }
];

// Solo mostrar checks si tenemos web (o el check de 'sin web')
const problemas = tieneWeb ? checks : [checks[0]];

// Resumen de debilidades
const debilidades = problemas.filter(c => !c.ok);
const seoResumen  = debilidades.length === 0
  ? 'Presencia online sólida. Pocas mejoras urgentes detectadas.'
  : `${debilidades.length} problema${debilidades.length > 1 ? 's' : ''} detectado${debilidades.length > 1 ? 's' : ''}: ${debilidades.slice(0,3).map(d => d.label.split('(')[0].trim()).join(', ')}.`;

// Datos para Supabase
const row = {
  place_id:         clinica['place_id'] || null,
  ciudad:           clinica.Ciudad      || '',
  nombre:           clinica.Nombre      || '',
  direccion:        clinica.Dirección   || clinica.Direccion || '',
  telefono:         clinica.Teléfono    || clinica.Telefono  || '',
  web:              clinica.Web         || '',
  email:            clinica.Email       || '',
  fuente_email:     clinica['Fuente Email'] || '',
  valoracion:       valoracion || null,
  n_resenas:        nResenas || 0,
  resumen:          clinica.Resumen     || '',
  estado:           clinica.Estado      || 'Nuevo',
  fecha_contacto:   clinica['Fecha contacto']        || null,
  n_seguimientos:   parseInt(clinica['Nº seguimientos'] || '0'),
  fecha_ultimo_contacto: clinica['Fecha último contacto'] || null,
  asunto_enviado:   clinica['Asunto enviado'] || '',
  seo_performance:  seoPerf  || null,
  seo_score:        seoScore || null,
  seo_problemas:    problemas,
  seo_resumen:      seoResumen,
  seo_analizado_at: new Date().toISOString(),
  updated_at:       new Date().toISOString()
};

return [{ json: { ...row, _supabaseUrl: config.SUPABASE_URL, _supabaseKey: config.SUPABASE_ANON_KEY } }];

// Limpia campos internos antes de enviar a Supabase
const item = $input.first().json;
const { _supabaseUrl, _supabaseKey, ...row } = item;
return [{ json: { row, _supabaseUrl, _supabaseKey } }];
